def thin():
    s=Side(border_style="thin",color="FFE0E0E0")
    return Border(left=s,right=s,top=s,bottom=s)

def hdr(cell,text,bg=DK,fg=WIT,sz=11,bold=True):
    cell.value=text
    cell.font=Font(name="Arial",bold=bold,size=sz,color=fg)
    cell.fill=PatternFill("solid",fgColor=bg)
    cell.alignment=Alignment(horizontal="center",vertical="center")
    cell.border=thin()

def cel(cell,val,align="center",bold=False,sz=10,clr="FF111111",bg=WIT,indent=0):
    cell.value=val
    cell.font=Font(name="Arial",bold=bold,size=sz,color=clr)
    cell.fill=PatternFill("solid",fgColor=bg)
    cell.alignment=Alignment(horizontal=align,vertical="center",indent=indent)
    cell.border=thin()

def maak_stand_tab(wb, tab_naam, titel, stand):
    ws=wb.create_sheet(tab_naam)
    ws.sheet_view.showGridLines=False
    ws.merge_cells("A1:K1")
    hdr(ws["A1"],titel,DK,WIT,12)
    ws.row_dimensions[1].height=34
    kop=["#","Club","G","W","GL","V","Pnt","Voor","Tgn","Doel±","W%"]
    brd=[5,26,6,6,6,6,8,7,7,8,7]
    for ci,(k,b) in enumerate(zip(kop,brd),1):
        hdr(ws.cell(row=2,column=ci),k,OR,WIT,10)
        ws.column_dimensions[get_column_letter(ci)].width=b
    ws.row_dimensions[2].height=22
    for i,t in enumerate(stand):
        row=i+3
        pos=t["pos"]; ds=t["ds"]
        wp=round(t["w"]/t["g"]*100) if t["g"]>0 else 0
        bg=(GOUD if pos==1 else EU if pos<=6 else DEG if pos>=17 else (ALT if i%2==0 else WIT))
        vals=[pos,t["naam"],t["g"],t["w"],t["gl"],t["v"],t["pnt"],
              t["voor"],t["tgn"],f"+{ds}" if ds>0 else str(ds),f"{wp}%"]
        for ci,val in enumerate(vals,1):
            c=ws.cell(row=row,column=ci)
            clr=("FF996600" if ci==1 and pos==1 else "FFE87722" if ci==7 else
                 "FF155724" if ci==10 and ds>0 else "FFC62828" if ci==10 and ds<0 else "FF222222")
            cel(c,val,"left" if ci==2 else "center",ci in [1,7],
                11 if ci==7 else 10,clr,bg,1 if ci==2 else 0)
        ws.row_dimensions[row].height=20
    ws.freeze_panes="A3"
    return ws

def maak_matrix_tab(wb, tab_naam, titel, matrix, teams_volgorde):
    wm=wb.create_sheet(tab_naam)
    wm.sheet_view.showGridLines=False
    mt=sorted(teams_volgorde)
    n=len(mt)
    wm.merge_cells(f"A1:{get_column_letter(n+1)}1")
    hdr(wm["A1"],titel,DK,WIT,11)
    wm.row_dimensions[1].height=30
    hdr(wm.cell(row=2,column=1),"THUIS ↓ / UIT →",DK,WIT,8)
    wm.column_dimensions["A"].width=22
    wm.row_dimensions[2].height=90
    for ci,team in enumerate(mt,2):
        c=wm.cell(row=2,column=ci)
        hdr(c,team,OR,WIT,8)
        c.alignment=Alignment(horizontal="center",vertical="bottom",text_rotation=90)
        wm.column_dimensions[get_column_letter(ci)].width=7
    for ri,thuis in enumerate(mt):
        row=ri+3
        cel(wm.cell(row=row,column=1),thuis,"left",True,9,"FF111111",ALT if ri%2==0 else WIT,1)
        wm.row_dimensions[row].height=18
        for ci,uit in enumerate(mt,2):
            c=wm.cell(row=row,column=ci); c.border=thin()
            c.alignment=Alignment(horizontal="center",vertical="center")
            if thuis==uit:
                cel(c,"—","center",False,9,"FF888888","FF2A2A2A")
            elif thuis in matrix and uit in matrix[thuis]:
                r=matrix[thuis][uit]
                hg,ag=(r[0],r[1]) if isinstance(r,list) else (r.split("-")[0],r.split("-")[1])
                hg,ag=int(hg),int(ag)
                c.value=f"{hg}-{ag}"
                if hg>ag: c.font=Font(name="Arial",bold=True,size=9,color="FF155724"); c.fill=PatternFill("solid",fgColor=WIN)
                elif hg<ag: c.font=Font(name="Arial",bold=True,size=9,color="FF721C24"); c.fill=PatternFill("solid",fgColor=VERLIES)
                else: c.font=Font(name="Arial",bold=True,size=9,color="FF856404"); c.fill=PatternFill("solid",fgColor=GELIJK)
            else:
                cel(c,"·","center",False,9,"FFCCCCCC",LG)
    leg=n+4
    wm.merge_cells(f"A{leg}:{get_column_letter(n+1)}{leg}")
    wm[f"A{leg}"]="🟢 Groen = Thuiswinst   🔴 Rood = Thuisverlies   🟡 Geel = Gelijk   · = Niet gespeeld"
    wm[f"A{leg}"].font=Font(name="Arial",size=9,italic=True,color="FF888888")
    wm.freeze_panes="B3"

